        // change resamples rather than wipes. (The Resolution slider keeps
        // its historical wipe — scale() without options is unchanged.)
        api.scale(p.scale, { preserve: true });
        api.advectionMode(p.advection);
        if (p.heatmap === false) api.wetnessHeatmap(false);
